SELECT issue_id
FROM issues
WHERE actual_hours = (SELECT MAX(actual_hours) FROM issues);

SELECT resolution
FROM issues
WHERE issue_id = 'specific_issue_id';

SELECT users.user_name, issues.*
FROM users
JOIN issues ON users.user_id = issues.assigned_to;

SELECT issue_id, feature, phase, description, status, category, priority
FROM issues
ORDER BY last_updated_on DESC;

SELECT category_name, priority_name
FROM categories, priorities
WHERE categories.category_id = '0' AND priorities.priority_id = '1';

SELECT DISTINCT u.user_name
FROM users u
JOIN comments c ON u.user_id = c.user_id;
